'use client';

/**
 * Página de Gestão de Tarefas
 */

import { useState } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Badge } from '@/components/ui/badge';
import { Checkbox } from '@/components/ui/checkbox';
import {
    CheckSquare,
    Plus,
    Search,
    Calendar,
    Clock,
    User,
    MoreVertical,
    Trash2
} from 'lucide-react';
import { toast } from '@/hooks/use-toast';
import {
    DropdownMenu,
    DropdownMenuContent,
    DropdownMenuItem,
    DropdownMenuTrigger,
} from '@/components/ui/dropdown-menu';
import {
    Dialog,
    DialogContent,
    DialogHeader,
    DialogTitle,
    DialogFooter,
} from '@/components/ui/dialog';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from '@/components/ui/select';

interface Task {
    id: string;
    title: string;
    description?: string;
    priority: 'low' | 'medium' | 'high';
    status: 'pending' | 'in_progress' | 'completed';
    dueDate?: string;
    assignee?: string;
}

export default function TasksPage() {
    const [tasks, setTasks] = useState<Task[]>([
        {
            id: '1',
            title: 'Confirmar consultas de amanhã',
            description: 'Ligar para pacientes e confirmar',
            priority: 'high',
            status: 'pending',
            dueDate: new Date().toISOString(),
        },
        {
            id: '2',
            title: 'Atualizar prontuário do paciente',
            priority: 'medium',
            status: 'in_progress',
        },
        {
            id: '3',
            title: 'Enviar relatório mensal',
            priority: 'low',
            status: 'completed',
        },
    ]);
    const [searchTerm, setSearchTerm] = useState('');
    const [showNewTaskDialog, setShowNewTaskDialog] = useState(false);
    const [newTask, setNewTask] = useState({
        title: '',
        description: '',
        priority: 'medium' as 'low' | 'medium' | 'high',
    });

    const filteredTasks = tasks.filter(task =>
        task.title.toLowerCase().includes(searchTerm.toLowerCase()) ||
        task.description?.toLowerCase().includes(searchTerm.toLowerCase())
    );

    const pendingTasks = tasks.filter(t => t.status === 'pending').length;
    const inProgressTasks = tasks.filter(t => t.status === 'in_progress').length;
    const completedTasks = tasks.filter(t => t.status === 'completed').length;

    const toggleTaskStatus = (taskId: string) => {
        setTasks(prev => prev.map(task => {
            if (task.id === taskId) {
                const newStatus = task.status === 'completed' ? 'pending' : 'completed';
                return { ...task, status: newStatus };
            }
            return task;
        }));
    };

    const deleteTask = (taskId: string) => {
        setTasks(prev => prev.filter(task => task.id !== taskId));
        toast({ title: 'Tarefa removida' });
    };

    const createTask = () => {
        if (!newTask.title.trim()) {
            toast({ variant: 'destructive', title: 'Título obrigatório' });
            return;
        }

        const task: Task = {
            id: Date.now().toString(),
            title: newTask.title,
            description: newTask.description,
            priority: newTask.priority,
            status: 'pending',
        };

        setTasks(prev => [task, ...prev]);
        setNewTask({ title: '', description: '', priority: 'medium' });
        setShowNewTaskDialog(false);
        toast({ title: 'Tarefa criada' });
    };

    const getPriorityColor = (priority: string) => {
        switch (priority) {
            case 'high': return 'bg-red-500';
            case 'medium': return 'bg-yellow-500';
            case 'low': return 'bg-green-500';
            default: return 'bg-gray-500';
        }
    };

    return (
        <div className="min-h-screen space-y-6">
            {/* Header */}
            <div className="flex items-center justify-between">
                <div className="flex items-center gap-4">
                    <div className="p-3 rounded-xl bg-primary/10">
                        <CheckSquare className="h-8 w-8 text-primary" />
                    </div>
                    <div>
                        <h1 className="text-3xl font-bold">Tarefas</h1>
                        <p className="text-muted-foreground">Gerencie suas tarefas e atividades</p>
                    </div>
                </div>
                <Button onClick={() => setShowNewTaskDialog(true)}>
                    <Plus className="h-4 w-4 mr-2" />
                    Nova Tarefa
                </Button>
            </div>

            {/* Stats */}
            <div className="grid gap-4 md:grid-cols-4">
                <Card>
                    <CardContent className="pt-6">
                        <div className="flex items-center justify-between">
                            <div>
                                <p className="text-sm text-muted-foreground">Total</p>
                                <p className="text-2xl font-bold">{tasks.length}</p>
                            </div>
                            <CheckSquare className="h-8 w-8 text-muted-foreground" />
                        </div>
                    </CardContent>
                </Card>
                <Card>
                    <CardContent className="pt-6">
                        <div className="flex items-center justify-between">
                            <div>
                                <p className="text-sm text-muted-foreground">Pendentes</p>
                                <p className="text-2xl font-bold text-yellow-500">{pendingTasks}</p>
                            </div>
                            <Clock className="h-8 w-8 text-yellow-500" />
                        </div>
                    </CardContent>
                </Card>
                <Card>
                    <CardContent className="pt-6">
                        <div className="flex items-center justify-between">
                            <div>
                                <p className="text-sm text-muted-foreground">Em Progresso</p>
                                <p className="text-2xl font-bold text-blue-500">{inProgressTasks}</p>
                            </div>
                            <Clock className="h-8 w-8 text-blue-500" />
                        </div>
                    </CardContent>
                </Card>
                <Card>
                    <CardContent className="pt-6">
                        <div className="flex items-center justify-between">
                            <div>
                                <p className="text-sm text-muted-foreground">Concluídas</p>
                                <p className="text-2xl font-bold text-green-500">{completedTasks}</p>
                            </div>
                            <CheckSquare className="h-8 w-8 text-green-500" />
                        </div>
                    </CardContent>
                </Card>
            </div>

            {/* Search */}
            <div className="relative">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                <Input
                    placeholder="Buscar tarefas..."
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    className="pl-10"
                />
            </div>

            {/* Task List */}
            <Card>
                <CardHeader>
                    <CardTitle>Lista de Tarefas</CardTitle>
                </CardHeader>
                <CardContent className="space-y-3">
                    {filteredTasks.length === 0 ? (
                        <p className="text-center text-muted-foreground py-8">
                            Nenhuma tarefa encontrada
                        </p>
                    ) : (
                        filteredTasks.map(task => (
                            <div
                                key={task.id}
                                className="flex items-center gap-4 p-4 border rounded-lg hover:bg-muted/50 transition-colors"
                            >
                                <Checkbox
                                    checked={task.status === 'completed'}
                                    onCheckedChange={() => toggleTaskStatus(task.id)}
                                />
                                <div className="flex-1">
                                    <p className={`font-medium ${task.status === 'completed' ? 'line-through text-muted-foreground' : ''}`}>
                                        {task.title}
                                    </p>
                                    {task.description && (
                                        <p className="text-sm text-muted-foreground">{task.description}</p>
                                    )}
                                </div>
                                <Badge className={getPriorityColor(task.priority)}>
                                    {task.priority === 'high' ? 'Alta' : task.priority === 'medium' ? 'Média' : 'Baixa'}
                                </Badge>
                                <DropdownMenu>
                                    <DropdownMenuTrigger asChild>
                                        <Button variant="ghost" size="icon">
                                            <MoreVertical className="h-4 w-4" />
                                        </Button>
                                    </DropdownMenuTrigger>
                                    <DropdownMenuContent align="end">
                                        <DropdownMenuItem
                                            className="text-red-600"
                                            onClick={() => deleteTask(task.id)}
                                        >
                                            <Trash2 className="h-4 w-4 mr-2" />
                                            Excluir
                                        </DropdownMenuItem>
                                    </DropdownMenuContent>
                                </DropdownMenu>
                            </div>
                        ))
                    )}
                </CardContent>
            </Card>

            {/* New Task Dialog */}
            <Dialog open={showNewTaskDialog} onOpenChange={setShowNewTaskDialog}>
                <DialogContent>
                    <DialogHeader>
                        <DialogTitle>Nova Tarefa</DialogTitle>
                    </DialogHeader>
                    <div className="space-y-4">
                        <div className="space-y-2">
                            <Label>Título</Label>
                            <Input
                                value={newTask.title}
                                onChange={(e) => setNewTask(prev => ({ ...prev, title: e.target.value }))}
                                placeholder="Título da tarefa"
                            />
                        </div>
                        <div className="space-y-2">
                            <Label>Descrição (opcional)</Label>
                            <Textarea
                                value={newTask.description}
                                onChange={(e) => setNewTask(prev => ({ ...prev, description: e.target.value }))}
                                placeholder="Descrição da tarefa"
                            />
                        </div>
                        <div className="space-y-2">
                            <Label>Prioridade</Label>
                            <Select
                                value={newTask.priority}
                                onValueChange={(v) => setNewTask(prev => ({ ...prev, priority: v as any }))}
                            >
                                <SelectTrigger>
                                    <SelectValue />
                                </SelectTrigger>
                                <SelectContent>
                                    <SelectItem value="low">Baixa</SelectItem>
                                    <SelectItem value="medium">Média</SelectItem>
                                    <SelectItem value="high">Alta</SelectItem>
                                </SelectContent>
                            </Select>
                        </div>
                    </div>
                    <DialogFooter>
                        <Button variant="outline" onClick={() => setShowNewTaskDialog(false)}>
                            Cancelar
                        </Button>
                        <Button onClick={createTask}>Criar Tarefa</Button>
                    </DialogFooter>
                </DialogContent>
            </Dialog>
        </div>
    );
}
