import { toast as sonnerToast } from "sonner"

type ToastProps = {
    title?: string
    description?: string
    variant?: "default" | "destructive"
    action?: React.ReactNode
}

// Direct toast function for use outside of components
export function toast({ title, description, variant, action }: ToastProps) {
    if (variant === "destructive") {
        sonnerToast.error(title, {
            description: description,
            action: action as unknown as React.ReactNode,
        })
    } else {
        sonnerToast.success(title, {
            description: description,
            action: action as unknown as React.ReactNode,
        })
    }
}

// Hook for use in components (maintains backward compatibility)
export function useToast() {
    return { toast }
}
